div.script:
                    window.addEventListener('DOMContentLoaded', function() {
                        var modal      = document.getElementById('kualeBranchModal');
                        var modalTitle = document.getElementById('kualeBranchTitle');
                        var modalMap   = document.getElementById('kualeBranchMap');
                        var modalClose = document.getElementById('kualeBranchClose');

                        document.querySelectorAll('.kuale-branch-link').forEach(function(link) {
                            link.addEventListener('click', function(e) {
                                e.preventDefault();
                                var branch  = this.getAttribute('data-branch');
                                var company = this.getAttribute('data-company');

                                if (!branch || branch === 'N/A') {
                                    modalTitle.textContent = 'Tamaulipas, México';
                                    modalMap.src = 'https://maps.google.com/maps?q=Tamaulipas+México&output=embed&hl=es&z=8';
                                } else {
                                    modalTitle.textContent = company + ' - ' + branch;
                                    var encodedQuery = encodeURIComponent(company + ' ' + branch + ' Tamaulipas México');
                                    modalMap.src = 'https://maps.google.com/maps?q=' + encodedQuery + '&output=embed&hl=es&z=15&iwloc=B';
                                }
                                modal.classList.add('is-open');
                            });
                        });

                        if (modalClose) {
                            modalClose.addEventListener('click', function() {
                                modal.classList.remove('is-open');
                                modalMap.src = '';
                            });
                        }

                        if (modal) {
                            modal.addEventListener('click', function(e) {
                                if (e.target === modal) {
                                    modal.classList.remove('is-open');
                                    modalMap.src = '';
                                }
                            });
                        }
                    });

                window.addEventListener('DOMContentLoaded', function() {

                    /* ── Ocultar header Odoo ── */
                    var header = document.getElementById('top');
                    if (header) header.style.display = 'none';

                    /* ── Badge de usuario ── */
                    var badge = document.getElementById('kualeUserBadge');
                    if (badge) {
                        badge.addEventListener('click', function(e) {
                            e.stopPropagation();
                            this.classList.toggle('is-open');
                        });
                        document.addEventListener('click', function() {
                            badge.classList.remove('is-open');
                        });
                    }

                    /* ════════════════════════════════════════
                       MAPA DE ESTATUS
                    ════════════════════════════════════════ */
                    var STAGE_MAP = {
                        'Nuevo': {
                            color: '#3498db',
                            tooltip: 'Tu solicitud fue recibida y está siendo revisada por el equipo de reclutamiento.'
                        },
                        'Calificación inicial': {
                            color: '#f39c12',
                            label: 'Hemos visto tu perfil',
                            tooltip: 'Estamos evaluando si tu perfil cumple con los requisitos básicos del puesto.'
                        },
                        'Prefiltrados': {
                            color: '#f39c12',
                            tooltip: 'Tu perfil pasó una revisión inicial y está siendo considerado para continuar en el proceso.'
                        },
                        'Primera entrevista': {
                            color: '#9b59b6',
                            tooltip: 'Estás en etapa de primera entrevista. Pronto nos pondremos en contacto para coordinar los detalles.'
                        },
                        'Segunda entrevista': {
                            color: '#9b59b6',
                            tooltip: 'Avanzaste a una segunda entrevista. El equipo quiere conocerte mejor antes de tomar una decisión.'
                        },
                        'Proceso de segunda entrevista': {
                            color: '#8e44ad',
                            tooltip: 'Tu candidatura está en evaluación profunda durante la segunda ronda de entrevistas.'
                        },
                        'Propuesta de contrato': {
                            color: '#1abc9c',
                            tooltip: '¡Muy buenas noticias! Estamos preparando una propuesta formal de trabajo para ti.'
                        },
                        'Proceso de contratación': {
                            color: '#1abc9c',
                            tooltip: 'Estás en la etapa final de incorporación. El equipo está gestionando los documentos necesarios.'
                        },
                        'Contrato firmado': {
                            color: '#27ae60',
                            tooltip: '¡Bienvenido/a! Tu contrato ha sido firmado. Recibirás instrucciones sobre tu fecha de inicio.'
                        },
                        'Rechazado': {
                            color: '#e74c3c',
                            label: 'Bolsa de trabajo',
                            tooltip: 'Por el momento nuestros puestos se encuentran ocupados, pero en cuanto se abra alguna vacante nos contactamos contigo.'
                        },
                        'abandoned': {
                            color: '#aaaaaa',
                            tooltip: 'Has decidido no continuar con este proceso. Puedes volver a aplicar cuando lo desees.'
                        },
                        'default': {
                            color: '#ff8800',
                            tooltip: 'Tu solicitud está en proceso interno. El equipo de reclutamiento te contactará pronto.'
                        }
                    };

                    /* ════════════════════════════════════════
                       TOOLTIP FLOTANTE ÚNICO
                    ════════════════════════════════════════ */
                    var tooltipEl = document.getElementById('kualeStatusTooltip');

                    function positionTooltip(e) {
                        var TW = 230, TH = 70, M = 14;
                        var x = e.clientX - TW / 2;
                        var y = e.clientY - TH - M;
                        x = Math.max(8, Math.min(x, window.innerWidth - TW - 8));
                        if (y < 8) { y = e.clientY + M + 6; }
                        tooltipEl.style.left = x + 'px';
                        tooltipEl.style.top  = y + 'px';
                    }

                    /* Aplicar color, tooltip y label a cada punto de estatus */
                    document.querySelectorAll('.kuale-status-dot').forEach(function(dot) {
                        var stage = dot.getAttribute('data-stage') || 'default';
                        var info  = STAGE_MAP[stage] || STAGE_MAP['default'];

                        /* Color del círculo */
                        dot.style.color = info.color;

                        /* Sustituir label en tabla si el mapa define uno (ej: Rechazado → Bolsa de trabajo) */
                        if (info.label) {
                            var badge = dot.closest('.kuale-status-badge');
                            if (badge) {
                                var labelEl = badge.querySelector('.kuale-status-label');
                                if (labelEl) { labelEl.textContent = info.label; }
                            }
                        }
                        /* Las etapas sin label en STAGE_MAP conservan el nombre real de la BD */

                        /* Eventos del tooltip flotante */
                        dot.addEventListener('mouseenter', function(e) {
                            tooltipEl.textContent = info.tooltip;
                            tooltipEl.classList.add('visible');
                            positionTooltip(e);
                        });
                        dot.addEventListener('mousemove', positionTooltip);
                        dot.addEventListener('mouseleave', function() {
                            tooltipEl.classList.remove('visible');
                        });
                    });

                    /* ════════════════════════════════════════
                       MODAL SEMÁFORO (botón ?)
                    ════════════════════════════════════════ */
                    var helpOverlay = document.getElementById('kualeStatusHelpOverlay');
                    var helpBtn     = document.getElementById('kualeStatusHelpBtn');
                    var helpClose   = document.getElementById('kualeStatusHelpClose');
                    var helpCloseX = document.getElementById('kualeStatusHelpCloseX');

                    if (helpCloseX) {
                        helpCloseX.addEventListener('click', function() {
                            helpOverlay.style.display = 'none';
                        });
                    }

                    if (helpBtn && helpOverlay) {
                        helpBtn.addEventListener('click', function(e) {
                            e.stopPropagation();
                            helpOverlay.style.display = 'flex';
                        });
                    }
                    if (helpClose) {
                        helpClose.addEventListener('click', function() {
                            helpOverlay.style.display = 'none';
                        });
                    }
                    if (helpOverlay) {
                        helpOverlay.addEventListener('click', function(e) {
                            if (e.target === helpOverlay) helpOverlay.style.display = 'none';
                        });
                    }

                    /* ════════════════════════════════════════
                       BOTÓN "QUITAR DE MI LISTA"
                       Guarda en BD y elimina la fila del DOM.
                    ════════════════════════════════════════ */
                    document.querySelectorAll('.kuale-btn-quitar-fila').forEach(function(btn) {
                        btn.addEventListener('click', function() {
                            tooltipEl.classList.remove('visible');
                            var row = this.closest('tr');
                            var appId = this.getAttribute('data-id');

                            fetch('/mis-aplicaciones/ocultar', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({
                                    jsonrpc: '2.0', method: 'call',
                                    params: { applicant_id: appId }
                                })
                            })
                            .then(function(r) { return r.json(); })
                            .then(function(data) {
                                var result = data.result || {};
                                if (result.success) {
                                    if (row) {
                                        row.style.transition = 'opacity .25s';
                                        row.style.opacity = '0';
                                        setTimeout(function() { row.remove(); }, 260);
                                    }
                                } else {
                                    console.error('Error al ocultar:', result.error);
                                }
                            })
                            .catch(function() {
                                console.error('Error de conexión al ocultar aplicación.');
                            });
                        });
                    });

                    /* ════════════════════════════════════════
                       MODAL ABANDONO DE PROCESO
                    ════════════════════════════════════════ */
                    var overlay      = document.getElementById('kualeAbandonOverlay');
                    var reason       = document.getElementById('kualeAbandonReason');
                    var comment      = document.getElementById('kualeAbandonComment');
                    var errorEl      = document.getElementById('kualeAbandonError');
                    var btnSend      = document.getElementById('kualeAbandonSend');
                    var btnCancel    = document.getElementById('kualeAbandonCancel');
                    var currentAppId = null;

                    reason.addEventListener('change', function() {
                        if (reason.value === 'bad_service' || reason.value === 'other') {
                            comment.style.display = 'block';
                        } else {
                            comment.style.display = 'none';
                            comment.value = '';
                        }
                        errorEl.style.display = 'none';
                    });

                    document.querySelectorAll('.kuale-btn-abandon').forEach(function(btn) {
                        btn.addEventListener('click', function() {
                            currentAppId = this.getAttribute('data-id');
                            reason.value = '';
                            comment.value = '';
                            comment.style.display = 'none';
                            errorEl.style.display = 'none';
                            overlay.style.display = 'flex';
                        });
                    });

                    btnCancel.addEventListener('click', function() {
                        overlay.style.display = 'none';
                    });

                    overlay.addEventListener('click', function(e) {
                        if (e.target === overlay) overlay.style.display = 'none';
                    });

                    btnSend.addEventListener('click', function() {
                        if (!reason.value) {
                            errorEl.textContent = 'Por favor selecciona un motivo.';
                            errorEl.style.display = 'block';
                            return;
                        }
                        if ((reason.value === 'bad_service' || reason.value === 'other') && !comment.value.trim()) {
                            errorEl.textContent = 'Por favor especifica el motivo.';
                            errorEl.style.display = 'block';
                            return;
                        }
                        btnSend.disabled = true;
                        btnSend.textContent = 'Enviando...';
                        fetch('/mis-aplicaciones/abandonar', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                jsonrpc: '2.0', method: 'call',
                                params: {
                                    applicant_id: currentAppId,
                                    reason:       reason.value,
                                    comment:      comment.value.trim()
                                }
                            })
                        })
                        .then(function(r) { return r.json(); })
                        .then(function(data) {
                            var result = data.result || {};
                            if (result.success) {
                                overlay.style.display = 'none';
                                window.location.reload();
                            } else {
                                errorEl.textContent = result.error || 'Error al procesar.';
                                errorEl.style.display = 'block';
                                btnSend.disabled = false;
                                btnSend.textContent = 'Enviar';
                            }
                        })
                        .catch(function() {
                            errorEl.textContent = 'Error de conexión. Intenta de nuevo.';
                            errorEl.style.display = 'block';
                            btnSend.disabled = false;
                            btnSend.textContent = 'Enviar';
                        });
                    });

                }); /* fin DOMContentLoaded */
